&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;🐋 🐬 🐶 🐱 🐭 🐹 🐰 🐻&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;🐼 🐨 🐯 🦁 🐮 🐷 🐽 🐸&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;🐵 🐴 🐔 🐧 🐦 🐣 🐤 🐥&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;❤️ ✨ ⭐  💔 💕 💖&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;💝 💗 💘  💚 💛&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;💞 💟 💡 💢 💣&lt;/td&gt;
